Write-Host "Patching frontend files..." -ForegroundColor Cyan

# src\lib\api.ts
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes("src\lib\api.ts", $b)

# vite.config.ts
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes("vite.config.ts", $b)

Write-Host "Done! Now restart the frontend:" -ForegroundColor Green
Write-Host "  Ctrl+C to stop, then: npm run dev" -ForegroundColor Yellow